import{_ as i,o as l,c as s,ak as e,as as t}from"./chunks/framework.24mNDJkT.js";const b=JSON.parse('{"title":"🌐 网络层核心协议 —— IP 协议","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/网络层/深入理解 IP 协议.md","filePath":"计算机网络/网络层/深入理解 IP 协议.md","lastUpdated":1775305895000}'),n={name:"计算机网络/网络层/深入理解 IP 协议.md"};function r(h,a,d,o,p,c){return l(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="🌐-网络层核心协议-——-ip-协议" tabindex="-1">🌐 网络层核心协议 —— IP 协议 <a class="header-anchor" href="#🌐-网络层核心协议-——-ip-协议" aria-label="Permalink to “🌐 网络层核心协议 —— IP 协议”">​</a></h1><h2 id="一、ip-协议概述" tabindex="-1">一、IP 协议概述 <a class="header-anchor" href="#一、ip-协议概述" aria-label="Permalink to “一、IP 协议概述”">​</a></h2><ul><li><strong>IP（Internet Protocol）= 网际协议</strong></li><li>在 TCP/IP 四层模型中属于： <ul><li><strong>网际层（网络层）核心协议</strong></li></ul></li><li>作用： <ul><li>实现<strong>跨网络的数据传输</strong></li><li>提供<strong>无连接、不可靠的分组传输服务</strong></li></ul></li></ul><p>📌 面试关键词：</p><ul><li>无连接（Connectionless）</li><li>尽力而为（Best Effort）</li><li>不保证可靠性（可能丢包、乱序）</li></ul><hr><h2 id="二、ip-数据报结构-重点" tabindex="-1">二、IP 数据报结构（重点） <a class="header-anchor" href="#二、ip-数据报结构-重点" aria-label="Permalink to “二、IP 数据报结构（重点）”">​</a></h2><h3 id="_1️⃣-基本结构" tabindex="-1">1️⃣ 基本结构 <a class="header-anchor" href="#_1️⃣-基本结构" aria-label="Permalink to “1️⃣ 基本结构”">​</a></h3><ul><li>每行：<strong>32 bit = 4 字节</strong></li><li>首部： <ul><li><strong>最小：20 字节</strong></li><li><strong>最大：60 字节</strong></li></ul></li><li>组成：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>固定部分（20B） + 可选字段（0~40B）</span></span></code></pre></div><hr><h2 id="三、首部字段详解-高频面试点" tabindex="-1">三、首部字段详解（高频面试点） <a class="header-anchor" href="#三、首部字段详解-高频面试点" aria-label="Permalink to “三、首部字段详解（高频面试点）”">​</a></h2><p><img src="'+t+`" alt="image-20260404202513515"></p><h3 id="_1️⃣-版本-version" tabindex="-1">1️⃣ 版本（Version） <a class="header-anchor" href="#_1️⃣-版本-version" aria-label="Permalink to “1️⃣ 版本（Version）”">​</a></h3><ul><li>表示 IP 协议版本</li><li>常见： <ul><li>IPv4 → 4</li><li>IPv6 → 6</li></ul></li></ul><hr><h3 id="_2️⃣-首部长度-ihl" tabindex="-1">2️⃣ 首部长度（IHL） <a class="header-anchor" href="#_2️⃣-首部长度-ihl" aria-label="Permalink to “2️⃣ 首部长度（IHL）”">​</a></h3><ul><li>单位：<strong>4 字节</strong></li><li>实际长度：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>首部长度 × 4</span></span></code></pre></div><p>📌 范围：</p><ul><li>最小：5 → 20B</li><li>最大：15 → 60B</li></ul><hr><h3 id="_3️⃣-总长度-total-length" tabindex="-1">3️⃣ 总长度（Total Length） <a class="header-anchor" href="#_3️⃣-总长度-total-length" aria-label="Permalink to “3️⃣ 总长度（Total Length）”">​</a></h3><ul><li>表示：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>IP数据报总长度 = 首部 + 数据</span></span></code></pre></div><p>📌 推导：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>数据长度 = 总长度 - 首部长度</span></span></code></pre></div><hr><h2 id="四、分片机制-🔥高频面试题" tabindex="-1">四、分片机制（🔥高频面试题） <a class="header-anchor" href="#四、分片机制-🔥高频面试题" aria-label="Permalink to “四、分片机制（🔥高频面试题）”">​</a></h2><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h3><ul><li>以太网 MTU = <strong>1500 字节</strong></li><li>IP 数据报可能 &gt; 1500 👉 必须 <strong>分片（Fragmentation）</strong></li></ul><hr><h3 id="_1️⃣-标识-identification" tabindex="-1">1️⃣ 标识（Identification） <a class="header-anchor" href="#_1️⃣-标识-identification" aria-label="Permalink to “1️⃣ 标识（Identification）”">​</a></h3><ul><li>同一个数据报的所有分片： <ul><li><strong>标识相同</strong></li></ul></li></ul><p>📌 作用： 👉 用于接收端<strong>重组数据</strong></p><hr><h3 id="_2️⃣-标志-flags" tabindex="-1">2️⃣ 标志（Flags） <a class="header-anchor" href="#_2️⃣-标志-flags" aria-label="Permalink to “2️⃣ 标志（Flags）”">​</a></h3><p>共 3 位：</p><table tabindex="0"><thead><tr><th>位</th><th>含义</th></tr></thead><tbody><tr><td>第1位</td><td>保留</td></tr><tr><td>第2位（DF）</td><td>是否允许分片</td></tr><tr><td>第3位（MF）</td><td>是否还有后续分片</td></tr></tbody></table><h4 id="关键逻辑" tabindex="-1">关键逻辑： <a class="header-anchor" href="#关键逻辑" aria-label="Permalink to “关键逻辑：”">​</a></h4><ul><li>DF = 1 → ❌ 不允许分片</li><li>MF = 1 → 后面还有分片</li><li>MF = 0 → 最后一片</li></ul><hr><h3 id="_3️⃣-片偏移-fragment-offset" tabindex="-1">3️⃣ 片偏移（Fragment Offset） <a class="header-anchor" href="#_3️⃣-片偏移-fragment-offset" aria-label="Permalink to “3️⃣ 片偏移（Fragment Offset）”">​</a></h3><ul><li>表示：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>当前分片在原数据中的位置</span></span></code></pre></div><p>📌 单位：</p><ul><li><strong>8字节</strong></li></ul><h4 id="示例" tabindex="-1">示例： <a class="header-anchor" href="#示例" aria-label="Permalink to “示例：”">​</a></h4><p>原数据：2000 字节 → 分2片</p><table tabindex="0"><thead><tr><th>分片</th><th>数据范围</th><th>偏移</th></tr></thead><tbody><tr><td>第1片</td><td>0~999</td><td>0</td></tr><tr><td>第2片</td><td>1000~1999</td><td>1000</td></tr></tbody></table><p>👉 接收端根据：</p><ul><li>标识 + 偏移 → 重组</li></ul><hr><h2 id="五、ttl-生存时间" tabindex="-1">五、TTL（生存时间） <a class="header-anchor" href="#五、ttl-生存时间" aria-label="Permalink to “五、TTL（生存时间）”">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to “定义”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TTL = 数据包最多能经过的路由器数量</span></span></code></pre></div><h3 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to “机制”">​</a></h3><ul><li>每经过一个路由器：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TTL - 1</span></span></code></pre></div><ul><li>当 TTL = 0： 👉 数据包被丢弃</li></ul><hr><h3 id="作用-面试重点" tabindex="-1">作用（面试重点） <a class="header-anchor" href="#作用-面试重点" aria-label="Permalink to “作用（面试重点）”">​</a></h3><p>👉 防止 <strong>路由环路</strong></p><h4 id="示例-1" tabindex="-1">示例： <a class="header-anchor" href="#示例-1" aria-label="Permalink to “示例：”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>A → 路由器1 → 路由器2 → 路由器1（循环）</span></span></code></pre></div><ul><li>如果没有 TTL → ❌ 无限循环</li><li>有 TTL → ✅ 自动销毁</li></ul><hr><h2 id="六、协议字段-protocol" tabindex="-1">六、协议字段（Protocol） <a class="header-anchor" href="#六、协议字段-protocol" aria-label="Permalink to “六、协议字段（Protocol）”">​</a></h2><h3 id="作用" tabindex="-1">作用 <a class="header-anchor" href="#作用" aria-label="Permalink to “作用”">​</a></h3><p>👉 指明上层协议类型</p><table tabindex="0"><thead><tr><th>值</th><th>协议</th></tr></thead><tbody><tr><td>6</td><td>TCP</td></tr><tr><td>17</td><td>UDP</td></tr><tr><td>1</td><td>ICMP</td></tr></tbody></table><p>📌 面试点：</p><ul><li>ping 使用的是： <ul><li><strong>ICMP</strong></li><li>但 <strong>封装在 IP 数据报中</strong></li></ul></li></ul><hr><h2 id="七、首部校验和-header-checksum" tabindex="-1">七、首部校验和（Header Checksum） <a class="header-anchor" href="#七、首部校验和-header-checksum" aria-label="Permalink to “七、首部校验和（Header Checksum）”">​</a></h2><ul><li>作用： 👉 检测 <strong>IP首部是否出错</strong></li></ul><p>📌 注意：</p><ul><li><strong>只校验首部</strong></li><li>不校验数据</li></ul><hr><h2 id="八、源地址-目的地址" tabindex="-1">八、源地址 &amp; 目的地址 <a class="header-anchor" href="#八、源地址-目的地址" aria-label="Permalink to “八、源地址 &amp; 目的地址”">​</a></h2><ul><li>各占 <strong>32 位（IPv4）</strong></li></ul><p>作用：</p><ul><li>标识发送方和接收方</li></ul><hr><h2 id="九、可选字段-填充-options-padding" tabindex="-1">九、可选字段 + 填充（Options + Padding） <a class="header-anchor" href="#九、可选字段-填充-options-padding" aria-label="Permalink to “九、可选字段 + 填充（Options + Padding）”">​</a></h2><h3 id="可选字段" tabindex="-1">可选字段 <a class="header-anchor" href="#可选字段" aria-label="Permalink to “可选字段”">​</a></h3><ul><li>可选功能（很少用）</li></ul><h3 id="填充-padding" tabindex="-1">填充（Padding） <a class="header-anchor" href="#填充-padding" aria-label="Permalink to “填充（Padding）”">​</a></h3><p>👉 保证：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>首部长度是 4 字节的整数倍</span></span></code></pre></div><p>📌 原因：</p><ul><li>IHL × 4 计算长度</li></ul><hr><h2 id="十、核心流程总结-面试高频" tabindex="-1">十、核心流程总结（面试高频） <a class="header-anchor" href="#十、核心流程总结-面试高频" aria-label="Permalink to “十、核心流程总结（面试高频）”">​</a></h2><h3 id="发送流程" tabindex="-1">发送流程： <a class="header-anchor" href="#发送流程" aria-label="Permalink to “发送流程：”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层数据</span></span>
<span class="line"><span>→ IP封装（加IP头）</span></span>
<span class="line"><span>→ 数据链路层封装</span></span>
<span class="line"><span>→ 物理层发送</span></span></code></pre></div><hr><h3 id="路由器处理流程" tabindex="-1">路由器处理流程： <a class="header-anchor" href="#路由器处理流程" aria-label="Permalink to “路由器处理流程：”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>收到数据帧</span></span>
<span class="line"><span>→ 去链路层头</span></span>
<span class="line"><span>→ 解析IP头</span></span>
<span class="line"><span>→ 查路由表</span></span>
<span class="line"><span>→ TTL-1</span></span>
<span class="line"><span>→ 重新封装</span></span>
<span class="line"><span>→ 转发</span></span></code></pre></div><hr><h3 id="接收流程" tabindex="-1">接收流程： <a class="header-anchor" href="#接收流程" aria-label="Permalink to “接收流程：”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>物理层 → 链路层 → 网络层</span></span>
<span class="line"><span>→ 去IP头</span></span>
<span class="line"><span>→ 上交传输层</span></span></code></pre></div><hr><h2 id="十一、面试高频总结" tabindex="-1">十一、面试高频总结 <a class="header-anchor" href="#十一、面试高频总结" aria-label="Permalink to “十一、面试高频总结”">​</a></h2><h3 id="⭐-必问点" tabindex="-1">⭐ 必问点 <a class="header-anchor" href="#⭐-必问点" aria-label="Permalink to “⭐ 必问点”">​</a></h3><ol><li>IP首部最小/最大长度？ <ul><li>20B / 60B</li></ul></li><li>为什么要分片？ <ul><li>MTU 限制（1500B）</li></ul></li><li>如何重组分片？ <ul><li>标识 + 片偏移</li></ul></li><li>TTL作用？ <ul><li>防止路由环路</li></ul></li><li>Protocol字段作用？ <ul><li>标识上层协议</li></ul></li><li>为什么首部长度要 ×4？ <ul><li>单位是 4 字节</li></ul></li></ol><hr><h2 id="十二、一句话总结-面试加分" tabindex="-1">十二、一句话总结（面试加分） <a class="header-anchor" href="#十二、一句话总结-面试加分" aria-label="Permalink to “十二、一句话总结（面试加分）”">​</a></h2><p>👉 <strong>IP协议的本质：</strong></p><blockquote><p>提供一种“尽力而为”的跨网络数据传输机制，通过IP地址实现寻址，通过路由实现路径选择，通过TTL避免死循环，通过分片机制适配不同网络的MTU限制。</p></blockquote>`,110)])])}const k=i(n,[["render",r]]);export{b as __pageData,k as default};
